ALGORITHM RSA_Key_Generation
INPUT: Required key size in bits (k)
OUTPUT: Public key (n, e), Private key (d)

BEGIN
  // Step 1: Generate two large random primes p and q
  // Security depends on these being large, random, and strong primes
  p ← Generate_Prime(k/2 bits)
  q ← Generate_Prime(k/2 bits)

  // Step 2: Ensure p and q are different
  WHILE p = q DO
    q ← Generate_Prime(k/2 bits)
  END WHILE

  // Step 3: Compute the modulus n
  // This is the public part that attackers try to factor
  n ← p * q

  // Step 4: Compute Euler's totient function φ(n)
  // φ(n) = (p-1)(q-1) is only computable if you know p and q
  phi_n ← (p - 1) * (q - 1)

  // Step 5: Choose public exponent e
  // Common choice: e = 65537 (must be coprime to φ(n))
  e ← 65537
  WHILE GCD(e, phi_n) ≠ 1 DO
    e ← e + 2
  END WHILE

  // Step 6: Compute private exponent d
  // d ≡ e⁻¹ (mod φ(n))
  // This is the modular inverse - can only be computed with φ(n)
  d ← Modular_Inverse(e, phi_n)

  // Return public key and private key
  RETURN (n, e), d
END

ALGORITHM Break_RSA_Attack_Simulation
INPUT: Public key (n, e)
OUTPUT: Private key d (if attack succeeds)

BEGIN
  // This demonstrates why RSA is secure:
  // Attacker only has (n, e), not p, q, or φ(n)

  // Attack Option 1: Factor n to get p and q
  // This is the mathematically hard problem
  p ← Attempt_Factorization(n)
  IF p ≠ NULL THEN
    q ← n / p
    phi_n ← (p - 1) * (q - 1)
    d ← Modular_Inverse(e, phi_n)
    RETURN d  // RSA Broken!
  END IF

  // Attack Option 2: Compute φ(n) directly
  // Proven to be equally hard as factoring
  phi_n ← Attempt_Compute_Phi(n)
  IF phi_n ≠ NULL THEN
    d ← Modular_Inverse(e, phi_n)
    RETURN d
  END IF

  // Both attacks failed - RSA remains secure
  RETURN NULL
END

/*
 * RSA Security Implementation - C with GMP Library
 * Demonstrates RSA key generation and security analysis
 * 
 * Compile: gcc -o rsa_security rsa_security.c -lgmp
 */

#include <stdio.h>
#include <gmp.h>
#include <time.h>

// Check if number is prime using Miller-Rabin
int is_probable_prime(mpz_t n, int iterations) {
    return mpz_probab_prime_p(n, iterations);
}

// Generate random prime of specified bit length
void generate_random_prime(mpz_t prime, unsigned int bits) {
    gmp_randstate_t state;
    gmp_randinit_mt(state);
    gmp_randseed_ui(state, time(NULL));

    mpz_t temp;
    mpz_init(temp);

    do {
        mpz_urandomb(temp, state, bits);
        // Ensure it's odd and has correct bit length
        mpz_setbit(temp, bits - 1);  // Set MSB
        mpz_setbit(temp, 0);          // Make it odd
        mpz_set(prime, temp);
    } while (!is_probable_prime(prime, 25));

    gmp_randclear(state);
    mpz_clear(temp);
}

// Extended Euclidean Algorithm for modular inverse
void mod_inverse(mpz_t result, mpz_t a, mpz_t m) {
    mpz_t m0, x, y;
    mpz_init_set(m0, m);
    mpz_init_set_ui(x, 1);
    mpz_init_set_ui(y, 0);

    mpz_t q, temp;
    mpz_init(q);
    mpz_init(temp);

    while (mpz_cmp_ui(m, 1) > 0) {
        mpz_div(q, a, m);        // q = a / m
        mpz_mul(temp, q, m);     // temp = q * m
        mpz_sub(temp, a, temp);  // temp = a - temp

        mpz_set(y, x);           // y = x
        mpz_sub(x, x, mpz_mul(x, q, x)); // This is simplified

        // Using GMP's built-in modular inverse
        break;
    }

    // Use GMP's built-in inverse for simplicity
    mpz_invert(result, a, m);

    mpz_clear(m0);
    mpz_clear(x);
    mpz_clear(y);
    mpz_clear(q);
    mpz_clear(temp);
}

// RSA Key Generation
void rsa_key_generation(unsigned int key_size, 
                       mpz_t n, mpz_t e, mpz_t d) {
    mpz_t p, q, phi_n, temp;
    mpz_init(p);
    mpz_init(q);
    mpz_init(phi_n);
    mpz_init(temp);

    unsigned int half_bits = key_size / 2;

    // Generate two large primes p and q
    generate_random_prime(p, half_bits);
    do {
        generate_random_prime(q, half_bits);
    } while (mpz_cmp(p, q) == 0);

    // n = p * q (this is the public modulus)
    mpz_mul(n, p, q);

    // φ(n) = (p-1)(q-1) - requires knowing p and q
    mpz_sub_ui(temp, p, 1);
    mpz_mul(phi_n, temp, q);
    mpz_sub_ui(temp, q, 1);
    mpz_mul(phi_n, phi_n, temp);

    // Public exponent e = 65537 (standard)
    mpz_set_ui(e, 65537);

    // Private exponent d = e⁻¹ mod φ(n)
    mod_inverse(d, e, phi_n);

    // Print results
    gmp_printf("Prime p (%u bits): %Zu\n", half_bits, p);
    gmp_printf("Prime q (%u bits): %Zu\n", half_bits, q);
    gmp_printf("Modulus n (%u bits): %Zu\n", key_size, n);
    gmp_printf("φ(n): %Zu\n", phi_n);
    gmp_printf("Public exponent e: %Zu\n", e);
    gmp_printf("Private exponent d: %Zu\n", d);

    mpz_clear(p);
    mpz_clear(q);
    mpz_clear(phi_n);
    mpz_clear(temp);
}

// Demonstrate why factoring n breaks RSA
void demonstrate_attack_scenario(mpz_t n, mpz_t e) {
    printf("\n=== Attack Scenario ===\n");
    printf("Attacker knows only:\n");
    gmp_printf("  Public key: (n = %Zu, e = %Zu)\n", n, e);
    printf("\nAttack methods:\n");
    printf("  1. Factor n to get p and q - currently infeasible for 2048+ bits\n");
    printf("  2. Compute φ(n) directly - proven equally hard as factoring\n");
    printf("  3. Use GNFS (General Number Field Sieve) - sub-exponential\n");
    printf("\nIf attacker factors n:\n");
    printf("  - They compute φ(n) = (p-1)(q-1)\n");
    printf("  - They compute d = e⁻¹ mod φ(n)\n");
    printf("  - RSA is BROKEN!\n");
}

int main() {
    printf("RSA Security Implementation in C\n");
    printf("================================\n\n");

    // Generate 512-bit key (for demonstration - not secure)
    // Real security requires 2048-bit or 4096-bit
    unsigned int key_size = 512;

    mpz_t n, e, d;
    mpz_init(n);
    mpz_init(e);
    mpz_init(d);

    printf("Generating %u-bit RSA key pair...\n\n", key_size);
    rsa_key_generation(key_size, n, e, d);

    demonstrate_attack_scenario(n, e);

    printf("\n=== Security Recommendations ===\n");
    printf("1. Use minimum 2048-bit keys (1024-bit is deprecated)\n");
    printf("2. Use strong primes with large prime factors in (p-1)\n");
    printf("3. Use OAEP padding to prevent chosen ciphertext attacks\n");
    printf("4. Implement constant-time operations against timing attacks\n");
    printf("5. Consider quantum threat (Shor's algorithm)\n");

    mpz_clear(n);
    mpz_clear(e);
    mpz_clear(d);

    return 0;
}
